+    local procedure PlanComponentsNotYetPlanned()
+    var
+        ComponentItem: Record Item;
+        RequisitionLine: Record "Requisition Line";
+        TempComponentToPlan: Record Item temporary;
+        TempSavedPlanningCompList: Record "Planning Component" temporary;
+        PlanningComponent: Record "Planning Component";
+    begin
+        // Save the current planning component list before planning components
+        if TempPlanningCompList.Find('-') then
+            repeat
+                TempSavedPlanningCompList := TempPlanningCompList;
+                TempSavedPlanningCompList.Insert();
+            until TempPlanningCompList.Next() = 0;
+
+        // Identify component items that were created but not planned yet
+        if TempSavedPlanningCompList.Find('-') then
+            repeat
+                // Check if this component has a requisition line
+                RequisitionLine.SetRange("Worksheet Template Name", CurrTemplateName);
+                RequisitionLine.SetRange("Journal Batch Name", CurrWorksheetName);
+                RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+                RequisitionLine.SetRange("No.", TempSavedPlanningCompList."Item No.");
+                RequisitionLine.SetRange("Variant Code", TempSavedPlanningCompList."Variant Code");
+                RequisitionLine.SetRange("Location Code", TempSavedPlanningCompList."Location Code");
+
+                if RequisitionLine.IsEmpty() then begin
+                    // Component hasn't been planned yet, add to list for planning
+                    if ComponentItem.Get(TempSavedPlanningCompList."Item No.") then begin
+                        if not TempComponentToPlan.Get(TempSavedPlanningCompList."Item No.") then begin
+                            TempComponentToPlan := ComponentItem;
+                            TempComponentToPlan."Variant Filter" := TempSavedPlanningCompList."Variant Code";
+                            TempComponentToPlan."Location Filter" := TempSavedPlanningCompList."Location Code";
+                            TempComponentToPlan.Insert();
+                        end;
+                    end;
+                end;
+            until TempSavedPlanningCompList.Next() = 0;
+
+        // Plan any components that weren't planned yet
+        if TempComponentToPlan.Find('-') then
+            repeat
+                PlanComponent(TempComponentToPlan);
+            until TempComponentToPlan.Next() = 0;
+
+        // Restore the saved planning component list
+        TempPlanningCompList.DeleteAll();
+        if TempSavedPlanningCompList.Find('-') then
+            repeat
+                TempPlanningCompList := TempSavedPlanningCompList;
+                TempPlanningCompList.Insert();
+            until TempSavedPlanningCompList.Next() = 0;
+    end;
+
+    local procedure PlanComponent(ComponentItem: Record Item)
+    var
+        ReqLineExtern: Record "Requisition Line";
+        PlanningAssignment: Record "Planning Assignment";
+    begin
+        // Delete existing requisition lines for this component if they don't reference a parent order
+        ReqLineExtern.SetCurrentKey(Type, "No.", "Variant Code", "Location Code");
+        ComponentItem.CopyFilter("Variant Filter", ReqLineExtern."Variant Code");
+        ComponentItem.CopyFilter("Location Filter", ReqLineExtern."Location Code");
+        ReqLineExtern.SetRange(Type, ReqLineExtern.Type::Item);
+        ReqLineExtern.SetRange("No.", ComponentItem."No.");
+        ReqLineExtern.SetRange("Worksheet Template Name", CurrTemplateName);
+        ReqLineExtern.SetRange("Journal Batch Name", CurrWorksheetName);
+        if ReqLineExtern.Find('-') then
+            repeat
+                ReqLineExtern.Delete(true);
+            until ReqLineExtern.Next() = 0;
+
+        // Plan the component item
+        Item.Copy(ComponentItem);
+        
+        CalculateAndGetPlanningCompList();
+
+        TempItemList := Item;
+        TempItemList.Insert();
+    end;
+
